INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (1,N'Avengers: Endgame',N'Hành động, Phiêu lưu',181,N'Sau sự kiện Infinity War, các Avengers còn lại tập hợp lại để đảo ngược thiệt hại Thanos gây ra trong vũ trụ.',N'https://upload.wikimedia.org/wikipedia/en/0/0d/Avengers_Endgame_poster.jpg','now_showing','4/26/2019',N'Anthony & Joe Russo','2026-06-11 00:34:50',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (2,N'Joker',N'Tội phạm, Kịch tính',122,N'Câu chuyện về nguồn gốc của tên phản diện Joker nổi tiếng trong vũ trụ DC.',N'https://upload.wikimedia.org/wikipedia/en/e/e1/Joker_%282019_film%29_poster.jpg','now_showing','10/4/2019',N'Todd Phillips','2026-06-11 00:34:50',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (4,N'Spider-Man: No Way Home',N'Siêu anh hùng, Phiêu lưu',148,N'Peter Parker nhờ Doctor Strange xóa ký ức về danh tính của mình, dẫn đến hậu quả không lường trước.',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781139194/moviebooking/movies/flewzijygdgwnydnwrkk.jpg','now_showing','12/17/2021',N'Jon Watts','2026-06-11 00:34:50',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (7,N'Top Gun: Maverick',N'Hành động, Kịch tính',130,N'Phi công huyền thoại Pete Mitchell tiếp tục bứt phá giới hạn.',N'https://upload.wikimedia.org/wikipedia/en/1/13/Top_Gun_Maverick_Poster.jpg','now_showing','5/27/2022',N'Joseph Kosinski','2026-06-11 00:34:50',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (8,N'Siêu Quậy Marsupilami (Houba! On the Trail of Marsupilami)',N'Hoạt hình, Hài hước, Phiêu lưu',105,N'Sau khi "làm mưa làm gió" tại phòng vé Pháp với hơn 6 triệu lượt vé, chú thú đốm đuôi dài huyền thoại Marsupilami đã chính thức đổ bộ rạp Việt. Phim mang lại tiếng cười bùng nổ, cực kỳ giải trí và phù hợp cho mọi lứa tuổi vào mùa hè này.',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781139906/moviebooking/movies/smbpsinzqidk7v06hdgw.png','now_showing','5/6/2026',N'Alain Chabat','2026-06-11 01:04:14',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (10,N'Tây Du Ký Đại Náo (Dị bản Thái Lan)',N'Hài hước, Hành động, Xuyên không',110,N'"Ông hoàng phòng vé" Thái Lan tái định nghĩa tác phẩm kinh điển. Tôn Ngộ Không bị quạt Ba Tiêu thổi bay... xuyên không thẳng xuống một bãi rác tại Bangkok thời hiện đại. Những màn tung hứng "nhây - bựa - lầy" đặc sản Thái Lan giữa Ngộ Không và Đường Tăng sẽ khiến bạn cười ra nước mắt.',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781142708/moviebooking/movies/qa9dsb6ojzeiffd6gcst.jpg','now_showing','6/1/2026',N'Poj Arnon','2026-06-11 01:24:16',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (11,N'Mạc Ly',N'Cổ trang, Tình cảm, Quyền mưu',45,N'Được chuyển thể từ tiểu thuyết Thịnh Thế Đích Phi, bộ phim đánh dấu màn hợp tác bùng nổ phản ứng hóa học giữa Bạch Lộc và Thừa Lỗi. Câu chuyện xoay quanh Diệp Ly - trưởng nữ mang mối thù gia tộc liên thủ cùng Định Vương Mặc Tu Nghiêu phá tan các âm mưu triều chính.',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781142763/moviebooking/movies/qi87qjdrls5rublxokxt.jpg','now_showing','6/9/2026',N'Cục chính kịch Tencent','2026-06-11 01:24:16',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (12,N'Đếm Ngày Xa Mẹ',N'Tâm lý, Gia đình, Tình cảm',105,N'Câu chuyện cảm động lấy đi nước mắt của khán giả về hành trình của người con đi làm xa xứ, đếm ngược từng ngày để trở về bên mẹ. Phim khai thác sâu sắc tình mẫu tử, sự hy sinh thầm lặng của người phụ nữ Việt Nam và những tiếc nuối của người trẻ trong guồng quay cơm áo gạo tiền.',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781142799/moviebooking/movies/f9syx8mnrw3yhacaxaju.jpg','coming_soon','6/12/2026',N'Lý Hải','2026-06-11 01:24:16',NULL);
INSERT INTO [Movies] (Id,Title,Genre,DurationMin,Description,PosterUrl,Status,ReleaseDate,Director,CreatedAt,TrailerUrl) VALUES (13,N'Song Hỷ Lâm Nguy',N'Hài hước, Tình cảm, Gia đình',95,N'Chuyện phim xoay quanh một đám cưới miệt vườn miền Tây "bất ổn" nhất màn ảnh khi hai gia đình thông gia vốn là oan gia ngõ hẹm. Hàng loạt tình huống dở khóc dở cười diễn ra ngay trong ngày rước dâu khiến ngày "Song hỷ" suýt biến thành "Lâm nguy".',N'https://res.cloudinary.com/dec5fefrn/image/upload/v1781142838/moviebooking/movies/tbka9wefmzqvyfdsoolg.jpg','now_showing','6/2/2026',N'Nhất Trung','2026-06-11 01:24:16',N'https://youtu.be/tqaPZSVHff4?si=xKA9F2lTaGLgoena');
